def range_summary(nums):
    if not nums:
        return ''
    nums = sorted(set(nums))
    summary = []
    i = 0
    while i < len(nums):
        start = i
        while i + 1 < len(nums) and nums[i] + 1 == nums[i + 1]:
            i += 1
        if start == i:
            summary.append(str(nums[start]))
        else:
            summary.append(f"{nums[start]}-{nums[i]}")
        i += 1
    return ','.join(summary)
